import{_ as t,c as e,o as a,ag as _}from"./chunks/framework.ELrfyV9R.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2025/2025-12-27-贸易战.md","filePath":"ai/2025/2025-12-27-贸易战.md","lastUpdated":1773962024000}'),o={name:"ai/2025/2025-12-27-贸易战.md"};function r(s,p,n,i,c,d){return a(),e("div",null,p[0]||(p[0]=[_("<p>2025年1月20日，特朗普上任后，就马不停蹄的开始策划对全球发动贸易战。</p><p>2025年2月1日，特朗普就宣布以芬太尼为由，对中国所有产品加征10%的关税。</p><p>2025年2月27日，美方进一步将芬太尼关税税率从10%提升至20%，并于3月4日起正式实施。</p><p>2025年4月3日，特朗普正式宣布将对所有国家征收10%的基准关税，再针对中国商品加征24%的关税，也就是这一轮总共加征34%的关税。</p><p>2025年4月7日，美方宣布将对我方额外再加征50%关税，4月9日生效。</p><p>2025年4月10日，特朗普再次宣布，将4月对我方加征的关税，从84%提高到125%，也就是再次加征41%的关税。</p><p>也就是2月1日 10% + 2月27日 10% + 4月3日 10% + 24% + 4月7日 50% + 4月10日 41% = 145%的关税。</p><p>再来看一下中国的反制。</p><p>2025年2月4日，我方对原产于美国的部分进口商品加征关税：1、对煤炭、液化天然气加征15%关税。2、对原油、农业机械、大排量汽车、皮卡加征10%关税。对谷歌反垄断调查；对钨、碲、铋、钼、铟相关物项实施出口管制；</p><p>2025年3月4日，我方对原产于美国的部分进口商品加征关税：1、对鸡肉、小麦、玉米、棉花加征15%关税；2、对高粱、大豆、猪肉、牛肉、水产品、水果、蔬菜、乳制品加征10%关税。此外也有其他一系列反制组合拳。</p><p>2025年4月4日，我方自2025年4月10日12时01分起，对原产于美国的所有进口商品，在现行适用关税税率基础上加征34%关税，其中基准关税10%，对等关税24%。</p><p>2025年4月7日，我方宣布将对我方额外加征50%关税，4月9日生效。</p><p>2025年4月11日，我方宣布自2025年4月12日起，调整对原产于美国的进口商品加征关税措施。由84%提高至125%。鉴于在目前关税水平下，美国输华商品已无市场接受可能性，如果美方后续对中国输美商品继续加征关税，中方将不予理会。</p><p>可以进行对比看看，从反制的角度基本上是对等反制了。</p><p>2025年5月9日，中美经贸团队在瑞士日内瓦举行了今年第一次磋商。</p><p>结果是：4月份第二次加的50%对等关税，这部分双方同步取消。第三次加的41%对等关税，这部分双方同步取消。 重点说一下第一次的：第一次加的10%基准关税+24%对等关税。这部分双方保留互相加的10%基准关税，24%对等关税暂停90天执行。</p><p>2025年6月9日，中美经贸团队在伦敦进行了今年第二次会晤，就“关税框架达成原则一致”。</p><p>2025年7月28日，中美经贸团队在瑞典斯德哥尔摩进行了第三次会晤，确认24%对等关税的暂缓期继续延长展期90天。</p><p>2025年9月14日，中美经贸团队在西班牙马德里进行了第四次会晤，就妥善解决TikTok问题达成基本框架共识。</p>",19)]))}const f=t(o,[["render",r]]);export{m as __pageData,f as default};
